+    /// `SSTORE`, with the redundant warm-cache reload elided on the opcode hot path.
+    ///
+    /// The `SSTORE` opcode handler runs `inspect_storage(spec, address, key)` immediately
+    /// before this `Host::sstore`, loading `address` into the journal state map and inserting
+    /// the `key` slot. revm's `JournalInner::sstore` then re-derives that exact slot with a
+    /// full `sload` (account lookup + storage `entry`) followed by two more `get_mut`
+    /// re-lookups — all redundant warm-cache hits against state the handler just populated.
+    /// When the slot is already resident we resolve it in a single storage-map pass,
+    /// reproducing `sload_with_account` + `JournalInner::sstore` for an already-present slot
+    /// byte-for-byte: the cold→warm journal entry, the change journal entry, the `is_cold`
+    /// flag, and the original/present values. Any case the fast path does not cover — account
+    /// or slot not resident (e.g. pre-Rex4 EIP-7702 storage delegation routes the load to the
+    /// delegate's storage), or an off-opcode caller — falls back to the verbatim revm
+    /// implementation, so behaviour is identical for every input.
+    fn sstore(
+        &mut self,
+        address: Address,
+        key: U256,
+        value: U256,
+    ) -> Option<StateLoad<SStoreResult>> {
+        let journal = &mut self.inner.journaled_state;
+        let transaction_id = journal.inner.transaction_id;
+        if let Some(account) = journal.inner.state.get_mut(&address) {
+            if let Some(slot) = account.storage.get_mut(&key) {
+                // Resident-slot hot path: mirror `JournalInner::sstore` for an Occupied slot.
+                // `sload` warms the slot and emits `StorageWarmed` when it was cold; the change
+                // logic emits `StorageChanged` and updates `present_value` only when the value
+                // actually differs. `is_created()` is read but unused by `sload` on this branch,
+                // so it is elided here with no observable effect.
+                let is_cold = slot.mark_warm_with_transaction_id(transaction_id);
+                let present_value = slot.present_value();
+                let original_value = slot.original_value();
+                let changed = present_value != value;
+                if changed {
+                    slot.present_value = value;
+                }
+                // INVARIANT: `original_value` is a distinct stored field, untouched by the
+                // `present_value` write — so reading it before the write (as done here) yields
+                // the same value revm reads after the write. Pin the one reordering this fast
+                // path relies on.
+                debug_assert_eq!(
+                    slot.original_value(),
+                    original_value,
+                    "SSTORE original_value must be independent of the present_value write",
+                );
+                // Journal-entry order matches revm: `StorageWarmed` (emitted inside `sload`)
+                // precedes `StorageChanged`. The slot borrow has ended, so these disjoint-field
+                // pushes are unambiguous.
+                if is_cold {
+                    journal.inner.journal.push(JournalEntry::StorageWarmed { address, key });
+                }
+                if changed {
+                    journal.inner.journal.push(JournalEntry::StorageChanged {
+                        address,
+                        key,
+                        had_value: present_value,
+                    });
+                }
+                return Some(StateLoad::new(
+                    SStoreResult { original_value, present_value, new_value: value },
+                    is_cold,
+                ));
+            }
+        }
+        // Account or slot not resident: defer to the verbatim revm path (handles the cold
+        // load, EIP-7702-delegated storage, and any DB-error stashing identically).
+        self.inner.sstore(address, key, value)
